 8→interface DeserializeResult {
 9→  nodes: FlowNode[];
10→  edges: FlowEdge[];
11→  direction: FlowDirection;
12→  nextIdCounter: number;
13→  componentDefinitions?: ComponentDefinition[];
14→}
