 88→  const [mermaidImportOpen, setMermaidImportOpen] = useState(false);
 89→  const [exportDialogOpen, setExportDialogOpen] = useState(false);
 90→  const [isBulkEditMode, setIsBulkEditMode] = useState(false);
 91→  const [bulkEditFocusTarget, setBulkEditFocusTarget] = useState<{
 92→    type: "node" | "edge";
