 96→  const [bulkEditSelectedIds, setBulkEditSelectedIds] = useState<string[]>([]);
 97→  const { t } = useLocale();
 98→  const isEditingComponent = useFlowStore((s) => !!s.editingComponentId);
 99→
100→  useAutoSave();
101→  useKeyboardShortcuts();
102→
103→  // Listen for export/import events
104→  useEffect(() => {
105→    const handleExportEvent = () => {
106→      setExportDialogOpen(true);
107→    };
108→
109→    const handleImportEvent = (e: Event) => {
110→      try {
111→        const content = (e as CustomEvent).detail as string;
112→        const result = deserialize(content);
113→        useFlowStore.getState().loadState(result);
114→        toast.success(locales[useLocaleStore.getState().locale]["importedSuccess"]);
115→      } catch (err) {
116→        toast.error(locales[useLocaleStore.getState().locale]["importFailed"]);
117→        console.error(err);
118→      }
119→    };
120→
121→    window.addEventListener("flowmaid:export", handleExportEvent);
122→    window.addEventListener("flowmaid:import", handleImportEvent);
123→    return () => {
124→      window.removeEventListener("flowmaid:export", handleExportEvent);
125→      window.removeEventListener("flowmaid:import", handleImportEvent);
126→    };
127→  }, []);
128→
129→  const handleExport = useCallback(() => {
130→    setExportDialogOpen(true);
131→  }, []);
132→
133→  const handleImport = useCallback(() => {
134→    fileInputRef.current?.click();
135→  }, []);
136→
137→  const handleFileChange = useCallback(
138→    (e: React.ChangeEvent<HTMLInputElement>) => {
139→      const file = e.target.files?.[0];
140→      if (!file) return;
141→      const reader = new FileReader();
142→      reader.onload = (ev) => {
143→        const content = ev.target?.result as string;
144→        window.dispatchEvent(
145→          new CustomEvent("flowmaid:import", { detail: content })
146→        );
147→      };
148→      reader.readAsText(file);
149→      e.target.value = "";
150→    },
151→    []
152→  );
153→
154→  const handleImportMermaid = useCallback(() => {
