160→  }, []);
161→
162→  const handleEnterBulkEdit = useCallback(() => {
163→    setBulkEditFocusTarget(null);
164→    setBulkEditHighlightId(null);
165→    setBulkEditSelectedIds([]);
166→    setIsBulkEditMode(true);
167→  }, []);
168→
169→  const handleExitBulkEdit = useCallback(() => {
170→    setIsBulkEditMode(false);
171→    setBulkEditFocusTarget(null);
172→    setBulkEditHighlightId(null);
173→    setBulkEditSelectedIds([]);
174→  }, []);
175→
176→  // Table row click → highlight + zoom
