187→  }, []);
188→
189→  // Canvas click → highlight only (no zoom)
190→  const handleBulkEditCanvasNodeClick = useCallback((nodeId: string) => {
191→    setBulkEditSelectedIds([]);
192→    setBulkEditFocusTarget(null);
193→    setBulkEditHighlightId(nodeId);
194→  }, []);
195→
196→  const handleBulkEditCanvasEdgeClick = useCallback((edgeId: string) => {
197→    setBulkEditSelectedIds([]);
198→    setBulkEditFocusTarget(null);
199→    setBulkEditHighlightId(edgeId);

200→  }, []);
201→
