221→          style={{
222→            padding: isEditingComponent ? '0.4% 1% 1% 1%' : '0',
223→            backgroundColor: isEditingComponent ? 'var(--foreground)' : 'transparent',
224→          }}
225→        >
226→          <div
227→            className="overflow-hidden transition-[max-height,opacity] duration-500 ease-in-out"
228→            style={{
229→              maxHeight: isEditingComponent ? '48px' : '0px',
230→              opacity: isEditingComponent ? 1 : 0,
231→            }}
232→          >
233→            <ComponentEditingHeader />
