235→          <div className={`flex-1 min-h-0 w-full flex flex-col transition-[border-radius] duration-500 ease-in-out overflow-hidden ${isEditingComponent ? 'rounded-lg bg-background' : ''}`}>
236→          <Toolbar
237→            onExport={isBulkEditMode ? undefined : handleExport}
