275→              isOpen={leftOpen}
276→              onToggle={toggleLeft}
277→              width={leftWidth}
278→              ribbonLabel="Nodes"
279→            >
280→              <NodePalette />
281→            </CollapsiblePanel>
282→
283→            <ResizablePanelGroup orientation="horizontal" className="flex-1">
